external_knowledge:
- A sensor's peak temperature refers to its maximum recorded temperature reading; 
- Average temperature represents the mean of all recorded temperature readings for a sensor;
- Uploads are considered successful when the upload status is 'successful'.

sql:
SELECT sensor_id, total_readings
FROM data_overview
ORDER BY total_readings DESC;

SELECT du.file_name, AVG(du.file_size) AS avg_upload_size
FROM data_uploads du
GROUP BY du.file_name;
